// Récupérer le binaire Word depuis le nœud précédent
const wordBinary = items[0].binary?.data?.data;

if (!wordBinary) {
  throw new Error('Aucun fichier Word généré');
}

// Retourner le Word en base64 dans le JSON
return {
  json: {
    success: true,
    wordBase64: wordBinary,
    message: 'Document généré avec succès'
  }
};
